import React from 'react';
import bullesDevImage from './requindev.png';
import './header.css';

const Header = () => {
  const scrollToSection = (sectionId) => {
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <header>
      <div className="bullesdev">
        <img src={bullesDevImage} alt="Les bulles du dev" />
      </div>
      <nav>
        <div className="liensnav">
          <p onClick={() => scrollToSection('accueil')}>Accueil</p>
          <p onClick={() => scrollToSection('pageQjs')}>Mon évolution</p>
          <p onClick={() => scrollToSection('competences')}>Mes compétences</p>
          <p onClick={() => scrollToSection('projets')}>Mes projets réalisés</p>
          <p onClick={() => scrollToSection('footer')}>Contact</p>
        </div>
      </nav>
    </header>
  );
};

export default Header;
